#include <stdio.h>

int build_error_msg(char *buf, size_t sz) {
    int code = 404;
    char *path = "/proc/42/status";
    int pid = 42;
    return snprintf(buf, sz, "[ERR-%d] Not found: %s (pid=%d)", code, path, pid);
}

int build_small_error(char *buf, size_t sz) {
    int pid = 42;
    return snprintf(buf, sz, "pid=%d cmd=%s", pid, "very_long_name_here");
}

validation.test_code:
void test_error_msg_content(void) {
    char buf[128];
    build_error_msg(buf, sizeof(buf));
    TEST_ASSERT_EQUAL_STRING("[ERR-404] Not found: /proc/42/status (pid=42)", buf);
}

void test_error_msg_length(void) {
    char buf[128];
    int ret = build_error_msg(buf, sizeof(buf));
    TEST_ASSERT_EQUAL_INT(44, ret);
}

void test_small_truncation_detected(void) {
    char buf[20];
    int ret = build_small_error(buf, sizeof(buf));
    TEST_ASSERT_TRUE(ret >= (int)sizeof(buf));
}

void test_small_truncation_content(void) {
    char buf[20];
    build_small_error(buf, sizeof(buf));
    TEST_ASSERT_EQUAL_INT(19, strlen(buf));
}

int main(void) {
    RUN_TEST(test_error_msg_content);
    RUN_TEST(test_error_msg_length);
    RUN_TEST(test_small_truncation_detected);
    RUN_TEST(test_small_truncation_content);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

